import { LedgerRecord } from '../base/ledger-record';
import { LedgerCustom } from '../common/ledger-custom';
import { LedgerBaseData } from '../common/ledger-data';
import { LedgerHandle } from '../common/ledger-handle';
/**
 * Ledger Metric record
 */
export type MetricRecord = LedgerRecord<LedgerMetric>;
/**
 * Metric label
 */
export type MetricParams = {
    [key: string]: string;
};
/**
 * Metrics represent individual generated metrics.
 */
export type LedgerMetric = LedgerBaseData & {
    /**
     * A handle that uniquely identifies a metric.
     */
    handle: LedgerHandle;
    /**
     * Labels assigned to the metric
     * definition.
     */
    params?: MetricParams;
    /**
     * Symbol of the metric. This represents the unit of the metric.
     * e.g. ms, anchors, etc.
     */
    symbol: string;
    /**
     * Custom metadata that can be stored alongside a metric
     * definition.
     */
    custom?: LedgerCustom;
};
export type MetricTimeseriesGroup = {
    /**
     * Group of the metric.
     */
    key: string;
    /**
     * Amount of the metric.
     */
    amount: number;
};
export type BaseMetricTimeseriesItem = {
    /**
     * Window of the metric.
     */
    window: {
        starts: string;
        closes: string;
    };
};
export type MetricGroupTimeseriesItem = BaseMetricTimeseriesItem & {
    /**
     * Groups of the timeseries item.
     */
    groups: MetricTimeseriesGroup[];
};
export type MetricBasicTimeseriesItem = BaseMetricTimeseriesItem & {
    /**
     * Amount of the metric.
     */
    amount: number;
};
export type MetricTimeseriesItem = MetricGroupTimeseriesItem | MetricBasicTimeseriesItem;
